function isTechnical(value) {
  return /^\s*<\s*(svg|style)\b/i.test(value)
    || /\b(function\s*\(|localStorage|sessionStorage|document\.|window\.|NodeFilter|MutationObserver)\b/.test(value)
    || /\b(color-mix|var\(--|grid-template|repeat\(|minmax\(|prefers-color-scheme)\b/.test(value)
    || /^&[a-z0-9_]+=/.test(value)
    || /https?:\/\//i.test(value)
    || /^\/?(api|admin|c3|services|operations|catalogue|management|import|search|help|portfolio|spirals)(\/|$|\?)/.test(value)
    || /^[a-z]+[A-Z][A-Za-z0-9]*$/.test(value)
    || /^[A-Z0-9_./:-]+$/.test(value) && value.length > 2 && !/\s/.test(value);
}

function preserveCase(source, replacement) {
  if (!source) return replacement;
  if (source.toUpperCase() === source) return replacement.toUpperCase();
  if (source[0] === source[0].toUpperCase()) return replacement[0].toUpperCase() + replacement.slice(1);
  return replacement;
}

function translateWords(text) {
  return text.replace(/[\p{L}][\p{L}'’-]*/gu, (word) => {
    if (ALLOWED_WORDS.has(word) || ALLOWED_WORDS.has(word.toUpperCase())) return word;
    const normalized = word.toLowerCase().replace(/[’']/g, '');
    const translated = WORDS.get(normalized);
    return translated ? preserveCase(word, translated) : word;
  });
}

function normalizeSpacing(text) {
  return text
    .replace(/\s+([,.:;!?])/g, '$1')
    .replace(/\( /g, '(')
    .replace(/ \)/g, ')')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function translate(source) {
  if (!source || isTechnical(source)) return source;
  if (EXACT.has(source)) return EXACT.get(source);

  let out = source;
  for (const [from, to] of PHRASES) {
    out = out.replace(new RegExp(`(?<![\\p{L}])${escapeRegExp(from)}(?![\\p{L}])`, 'gu'), to);
  }
  out = translateWords(out);
  return normalizeSpacing(out);
}

const catalog = JSON.parse(fs.readFileSync(CATALOG_PATH, 'utf8'));
let changed = 0;
for (const entry of catalog.entries) {
  const next = translate(entry.source);
  if (next && entry.cs !== next) {
    entry.cs = next;
    changed += 1;
  }
  if (!entry.en) entry.en = entry.source;
}
fs.writeFileSync(CATALOG_PATH, `${JSON.stringify(catalog, null, 2)}\n`, 'utf8');
console.log(`updated Czech legacy translations: ${changed}`);
